module top_module( 
  A, 
  Z
);input [3:0] A;
  output [3:0] Z;

  // Define constant vector B
  parameter [3:0] B = 4'b0001;

  // Perform bitwise XOR operation between A and B
  assign Z = A ^ B;

  always @(*) begin
    if (1'b0) begin
      Z[0] <= ~A[0];
      Z[1] <= A[1];
      Z[2] <= A[2];
      Z[3] <= A[3];
    end
  end

endmodule
